export function generateBookingId(): string {
  const prefix = 'TT';
  const random = Math.floor(10000 + Math.random() * 90000);
  return `${prefix}-${random}`;
}

export function calculateTotalCost(
  destinationPrice: number,
  numberOfPersons: number,
  transportId: string,
  foodId: string,
  numberOfDays: number = 3
): number {
  const transport = transportOptions.find(t => t.id === transportId);
  const food = foodOptions.find(f => f.id === foodId);
  
  let transportCost = transport?.basePrice || 0;
  if (transportId === 'CAR') {
    transportCost += 500 * 2; // Average distance supplement
  }
  
  const foodCost = (food?.perDayCost || 0) * numberOfDays * numberOfPersons;
  const baseCost = destinationPrice * numberOfPersons;
  const serviceFee = 500;
  
  return baseCost + transportCost + foodCost + serviceFee;
}
